async function main() {
  let updated = 0, errors = 0;
  for (const m of modelsSeo) {
    try {
      const brand = await prisma.brand.findUnique({ where: { slug_category: { slug: m.brand, category: m.cat } }, include: { models: true } });
      if (!brand) { console.error("✗ Brand not found:", m.brand, m.cat); errors++; continue; }
      const model = brand.models.find(mod => mod.name === m.model);
      if (!model) { console.error("✗ Model not found:", m.brand, m.model); errors++; continue; }
      await prisma.model.update({ where: { id: model.id }, data: { metaTitle: m.metaTitle, metaDesc: m.metaDesc, h2Top: m.h2Top, descriptionTop: m.descriptionTop, h2Bottom: m.h2Bottom, descriptionBottom: m.descriptionBottom } });
      updated++;
      console.log("✓", m.brand, ">", m.model);
    } catch (err) { errors++; console.error("✗", m.brand, ">", m.model, ":", err.message); }
  }
  console.log("\nPart 4:", updated, "updates,", errors, "errors");
}
main().catch(console.error).finally(() => prisma.$disconnect());
